with open(locals()['var_function-call-16848582328649646875'], 'r') as f:
    patents_data = json.load(f)

# Regexes
assignee_patterns = [
    re.compile(r"^(.*?)\s+holds the", re.IGNORECASE),
    re.compile(r"is assigned to\s+(.*?)\s+and", re.IGNORECASE),
    re.compile(r"is owned by\s+(.*?)\s+and", re.IGNORECASE),
    re.compile(r"held by\s+(.*?)(?:,|\s+and)", re.IGNORECASE),
    re.compile(r"belonging to\s+(.*?)\s+and", re.IGNORECASE)
]

results = []
seen = set()

# Debug first row
# if len(patents_data) > 0:
#     print(f"Type of citation in row 0: {type(patents_data[0].get('citation'))}")

for row in patents_data:
    citations = row.get('citation')
    if not citations:
        continue

    cit_list = []
    if isinstance(citations, str):
        try:
            cit_list = json.loads(citations)
        except:
            continue
    elif isinstance(citations, list):
        cit_list = citations
    else:
        continue

    cites_uc = False
    for cit in cit_list:
        if isinstance(cit, dict) and cit.get('publication_number') in uc_pub_numbers:
            cites_uc = True
            break

    if cites_uc:
        info = row.get('Patents_info', '')
        assignee = None
        for p in assignee_patterns:
            m = p.search(info)
            if m:
                assignee = m.group(1).strip()
                break

        if assignee and "UNIV CALIFORNIA" not in assignee.upper():
            cpc_val = row.get('cpc')
            cpc_list = []
            if isinstance(cpc_val, str):
                try:
                    cpc_list = json.loads(cpc_val)
                except:
                    pass
            elif isinstance(cpc_val, list):
                cpc_list = cpc_val

            if cpc_list:
                primary_code = None
                for c in cpc_list:
                    if isinstance(c, dict):
                        if c.get('first') is True:
                            primary_code = c.get('code')
                            break
                if not primary_code and len(cpc_list) > 0 and isinstance(cpc_list[0], dict):
                    primary_code = cpc_list[0].get('code')

                if primary_code:
                    subclass = primary_code[:4]
                    if (assignee, subclass) not in seen:
                        results.append({"assignee": assignee, "subclass": subclass})
                        seen.add((assignee, subclass))

print("__RESULT__:")
print(json.dumps(results))

